const j = $input.item.json;
let mensaje = '', remitente = '';
try {
  const m = (j.messages && j.messages[0]) || (j.entry && j.entry[0].changes[0].value.messages[0]);
  mensaje = m.text ? m.text.body : (m.body || '');
  remitente = m.from || '';
} catch (e) { mensaje = j.message || ''; }
return { json: { origen: 'whatsapp', canal: 'WhatsApp', producto: '', agencia: '', mensaje, cliente: { telefono: remitente }, remitente } };

const b = $input.item.json.body || $input.item.json;
let canal = b.object === 'instagram' ? 'Instagram' : 'Facebook';
let mensaje = '', remitente = '';
try {
  const ev = b.entry[0].messaging[0];
  mensaje = ev.message ? (ev.message.text || '') : '';
  remitente = ev.sender ? ev.sender.id : '';
} catch (e) { mensaje = b.mensaje || ''; canal = b.canal || canal; }
return { json: { origen: 'meta', canal, producto: '', agencia: '', mensaje, cliente: { id: remitente }, remitente } };

const b = $input.item.json.body || $input.item.json;
const cli = b.cliente || {};
return { json: { origen: 'demo', canal: b.canal || 'Demo', producto: b.producto || '', agencia: b.agencia || '', mensaje: b.mensaje || '', cliente: cli, remitente: b.remitente || cli.telefono || cli.id || '', historial: b.historial || '' } };

const j = $input.item.json;
const cliente = j.cliente || {};
let texto = (j.mensaje || '').toString();
const mapa = {};
function tk(v, p) { if (!v) return; const t = '{' + p + '_001}'; mapa[t] = v; if (texto.includes(v)) texto = texto.split(v).join(t); }
tk(cliente.nombre, 'NAME'); tk(cliente.ci, 'CI'); tk(cliente.cuenta, 'ACCT'); tk(cliente.telefono, 'PHONE');
return { json: { ...j, texto_tokenizado: texto, mapa_tokens: mapa, cliente_visible: { nombre: cliente.nombre || null, ci: cliente.ci || null } } };

// Usa la IA si devolvio JSON valido; si no, REGLAS.
const base = $('Tokenizar (PII)').item.json;
const resp = $input.item.json;
let tipo, producto, categoria, severidad, firma, fuente = 'reglas';
try {
  let txt = '';
  if (resp && resp.choices && resp.choices[0] && resp.choices[0].message) txt = resp.choices[0].message.content || '';
  else if (resp && resp.content && resp.content[0] && resp.content[0].text) txt = resp.content[0].text;
  if (txt) { const a = txt.indexOf('{'), b = txt.lastIndexOf('}'); if (a>=0 && b>a) { const c = JSON.parse(txt.slice(a,b+1)); if (c.tipo) { tipo=c.tipo; producto=c.producto; categoria=c.categoria; severidad=c.severidad; firma=c.firma; fuente='ia (groq)'; } } }
} catch(e) {}
if (!tipo) {
  const t = (base.texto_tokenizado||'').toLowerCase();
  producto = base.producto || 'desconocido';
  if (t.includes('altoke')||t.includes('qr')) producto='altoke'; else if (t.includes('appsol')) producto='appSol'; else if (t.includes('solnet')) producto='Solnet';
  tipo='queja'; severidad='baja'; categoria='general';
  const con=[['cambie de celular','cambié de celular','cambie de dispositivo','nuevo celular','nuevo dispositivo'],['escanear','carnet','extranjero'],['sigue saliendo la deuda','sigue la deuda','no me han devuelto','ya pague','pague y sigue']];
  const cat=['acceso','acceso','transacciones']; let ok=false;
  for (let i=0;i<con.length;i++){ if(con[i].some(x=>t.includes(x))){ok=true;categoria=cat[i];break;} }
  if(!ok){ const se=['no puedo entrar','no puedo iniciar','no inicia','no carga','no funciona','caido','caida','no puedo transferir','qr no','no procesa','error general','se cae','app caida','no puedo acceder','no anda','nadie puede']; const cr=['login','iniciar sesion','transferencia','transferir','qr','ach'];
    if(se.some(k=>t.includes(k))){tipo='incidente';severidad='alta';}
    if(cr.some(k=>t.includes(k))&&(t.includes('no ')||t.includes('error')||t.includes('falla'))){tipo='incidente';severidad='alta';}
    if(t.includes('transfer')||t.includes('pago')||t.includes('qr'))categoria='transacciones'; else if(t.includes('iniciar')||t.includes('login')||t.includes('entrar')||t.includes('sesion')||t.includes('acceso'))categoria='acceso'; else if(t.includes('lento')||t.includes('demora')||t.includes('timeout'))categoria='rendimiento'; else if(t.includes('saldo')||t.includes('movimiento')||t.includes('comprobante'))categoria='datos';
  }
}
if (tipo!=='queja' && tipo!=='incidente') tipo='queja';
if (!firma) firma = (producto||'x') + '_' + (categoria||'general');
firma = String(firma).toLowerCase().replace(/[^a-z0-9_]+/g,'_').replace(/^_+|_+$/g,'');
return { json: { ...base, tipo, severidad: severidad||'baja', producto: producto||'desconocido', categoria: categoria||'general', firma, clasificado_por: fuente } };

// AGRUPAR por FIRMA (semantico) + CONTAR + ESCALAR severidad por afectados
const j = $input.item.json;
const sd = $getWorkflowStaticData('global');
sd.incidentes = sd.incidentes || {};
if (j.tipo === 'incidente') {
  const clave = (j.producto||'x') + '|' + (j.firma||'general');
  if (!sd.incidentes[clave]) { sd.incidentes[clave] = { caso_id: 'INC-' + Date.now().toString().slice(-5), afectados: 0 }; }
  sd.incidentes[clave].afectados += 1;
  j.caso_id = sd.incidentes[clave].caso_id;
  j.afectados = sd.incidentes[clave].afectados;
  j.incidente_nuevo = sd.incidentes[clave].afectados === 1;
  j.clave_incidente = clave;
  // Escalar severidad segun impacto real
  if (j.afectados >= 10) j.severidad = 'critica';
  else if (j.afectados >= 3 && j.severidad === 'baja') j.severidad = 'media';
} else {
  j.caso_id = 'QJA-' + Date.now().toString().slice(-5);
  j.afectados = 1;
}
return { json: j };

const j = $input.item.json;
let equipo = 'Mesa de Incidentes TI';
if (j.categoria === 'transacciones' || j.producto === 'altoke') equipo = 'Equipo Pagos/QR';
else if (j.categoria === 'acceso') equipo = 'Equipo Seguridad/Accesos';
else if (j.categoria === 'rendimiento') equipo = 'Infraestructura/TI';
else if (j.producto === 'appSol' || j.producto === 'Solnet') equipo = 'DevOps Aplicaciones';
return { json: { ...j, resultado: 'INCIDENTE', estado: 'En análisis', equipo_asignado: equipo, paquete_para_desarrollo: { que_falla: (j.categoria||'general')+' en '+(j.producto||'desconocido'), firma: j.firma, producto: j.producto, severidad: j.severidad, afectados: j.afectados, incidente_nuevo: j.incidente_nuevo, datos_para_reproducir: { canal: j.canal, producto: j.producto, agencia: j.agencia, texto_tokenizado: j.texto_tokenizado }, equipo_asignado: equipo, estado: 'En análisis' }, respuesta_cliente: 'Recibimos tu reporte. Lo vinculamos al incidente '+j.caso_id+' (afectados: '+j.afectados+'). Lo derivamos a '+equipo+'. Te avisaremos por este mismo canal. Estado: En análisis.' } };

// RESPUESTA QUEJA - LEE EL PLAYBOOK VIVO (compartido con Resolver)
const j = $input.item.json;
const sd = $getWorkflowStaticData('global');
sd.playbook = sd.playbook || {};
const defaults = {
  acceso: { pasos: ['1. Cierra y vuelve a abrir la app','2. Si cambiaste de dispositivo, reactiva tus tokens','3. Si persiste, vuelve a escanear tu carnet'], respuesta: 'Para resolver tu acceso: reactiva tus tokens o vuelve a escanear tu carnet siguiendo los pasos.' },
  transacciones: { pasos: ['1. Verifica tu comprobante','2. Espera el transcurso del día (conciliación)','3. Si no se refleja, te contactamos'], respuesta: 'Tu operación está en proceso. Espera el transcurso del día; se reflejará tras la conciliación.' },
  rendimiento: { pasos: ['1. Revisa tu conexión','2. Cierra otras apps','3. Actualiza la app'], respuesta: 'Puede ser conexión o versión. Sigue los pasos; si continúa, avísanos.' },
  datos: { pasos: ['1. Refresca la pantalla','2. Espera unos minutos','3. Si no aparece, te ayudamos'], respuesta: 'Tu información puede tardar en actualizarse. Refresca; si no aparece, escríbenos.' },
  general: { pasos: ['1. Revisa tu conexión','2. Actualiza la app'], respuesta: 'Gracias por tu consulta. Sigue los pasos; si continúa, escríbenos.' }
};
const clave = (j.producto||'x') + '|' + (j.categoria||'general');
const vivo = sd.playbook[clave];
let pasos, respuesta, version;
if (vivo) { pasos = vivo.pasos; respuesta = vivo.respuesta; version = 'v' + vivo.version + ' (vivo)'; }
else { const pb = defaults[j.categoria] || defaults.general; pasos = pb.pasos; respuesta = pb.respuesta; version = 'v1 (base)'; }
return { json: { ...j, resultado: (j.tipo === 'consulta' ? 'CONSULTA' : 'QUEJA'), estado: (j.tipo === 'consulta' ? 'Respondido' : 'Resuelto (autoservicio)'), equipo_asignado: 'Ninguno (autoservicio)', playbook_version: version, respuesta_cliente: respuesta, pasos } };

const j = $input.item.json;
const sd = $getWorkflowStaticData('global');
sd.casos = sd.casos || [];
sd.metricas = sd.metricas || { total: 0, quejas: 0, incidentes: 0 };
sd.metricas.total += 1;
if (j.resultado === 'INCIDENTE') sd.metricas.incidentes += 1; else sd.metricas.quejas += 1;
sd.casos.push({ caso_id: j.caso_id, tipo: j.resultado, producto: j.producto, categoria: j.categoria, firma: j.firma, estado: j.estado, canal: j.canal, afectados: j.afectados, equipo: j.equipo_asignado, ia: j.clasificado_por, ts: new Date().toISOString() });
if (sd.casos.length > 500) sd.casos = sd.casos.slice(-500);
j.metricas = sd.metricas;
return { json: j };

const base = $('Registrar Estado y Metricas').item.json;
const resp = $input.item.json;
let txt = '';
try { if (resp && resp.choices && resp.choices[0] && resp.choices[0].message) txt = (resp.choices[0].message.content || '').trim(); } catch (e) {}
if (txt) {
  let t = txt.replace(/```/g, '').trim(); let cliente = t, tecnico = ''; const idx = t.indexOf('---'); if (idx >= 0) { cliente = t.slice(0, idx); tecnico = t.slice(idx + 3); } cliente = cliente.replace(/^\s*(mensaje\s+para\s+el\s+cliente|cliente)\s*:?\s*/i, '').trim(); tecnico = tecnico.replace(/^\s*(parte\s+tecnica|tecnico)\s*:?\s*/i, '').trim(); if (cliente) base.respuesta_cliente = cliente; base.respuesta_ia = true; if (tecnico) base.recomendacion_tecnica = tecnico;
}
return { json: base };

const j = $input.item.json.body || $input.item.json;
const sol = (j.solucion || '').toString().trim();
let pasos = sol.split(/[\n.;]+/).map(s => s.trim()).filter(s => s.length > 3).map((s, i) => (i + 1) + '. ' + s.charAt(0).toUpperCase() + s.slice(1));
if (pasos.length === 0) pasos = ['1. ' + (sol || 'Sin detalle')];
return { json: { caso_id: j.caso_id || 'INC-?', producto: j.producto || 'desconocido', categoria: j.categoria || 'general', severidad: j.severidad || 'alta', afectados: j.afectados || 0, duracion_min: j.duracion_min || null, solucion_original: sol, pasos } };

// PUBLICAR AL PLAYBOOK VIVO (misma static data que lee Respuesta Queja)
const j = $input.item.json;
const sd = $getWorkflowStaticData('global');
sd.playbook = sd.playbook || {};
const clave = (j.producto||'x') + '|' + (j.categoria||'general');
const prev = sd.playbook[clave];
const version = prev ? prev.version + 1 : 1;
const respuesta = 'Solución validada por el equipo: ' + j.pasos.join(' ');
sd.playbook[clave] = { version, pasos: j.pasos, respuesta, actualizado: new Date().toISOString(), caso_id: j.caso_id };
return { json: { ...j, playbook: { clave, version, pasos: j.pasos, respuesta, estado: version > 1 ? 'actualizado (v'+version+')' : 'creado (v1)' } } };

const j = $input.item.json;
const fecha = new Date().toISOString().slice(0,10);
const informe = { numero: 'ASFI-'+(j.caso_id||'').replace('INC-','')+'-'+fecha.replace(/-/g,''), fecha, tipo_incidente: (j.categoria||'general')+' en '+(j.producto||'desconocido'), severidad: j.severidad, clientes_afectados: j.afectados, duracion_minutos: j.duracion_min, que_paso: 'Incidente '+j.caso_id+' de tipo '+j.categoria+' en '+j.producto+', severidad '+j.severidad+', con '+j.afectados+' afectado(s).', como_se_resolvio: j.solucion_original, acciones_preventivas: j.pasos, estado: 'BORRADOR — pendiente de aprobación humana' };
return { json: { resultado: 'CICLO CERRADO', caso_id: j.caso_id, playbook: j.playbook, informe_asfi: informe, mensaje: 'Solución publicada al Playbook '+j.playbook.estado+' y borrador de informe ASFI generado ('+informe.numero+').' } };
